dtsPropsFor.KebabMenu:
/** Called when the Edit item is chosen; the Edit item only shows when this is set. */
  onEdit?: () => void;
  /** Called when the Delete item is chosen; the Delete item only shows when this is set. */
  onDelete?: () => void;
  /** Label for the edit item. @default 'Edit' */
  editLabel?: string;
  /** Label for the delete item. @default 'Delete' */
  deleteLabel?: string;
  className?: string;

dtsPropsFor.ConfirmModal:
/** Heading. @default 'Delete?' */
  title?: string;
  /** Body message. @default "This can't be undone." */
  message?: string;
  /** Optional item name/summary shown in a chip below the message. */
  detail?: string;
  /** Confirm button label. @default 'Delete' */
  confirmLabel?: string;
  /** Called when the confirm (danger) button is clicked. */
  onConfirm?: () => void;
  /** Called on cancel, backdrop click, or Escape. */
  onClose?: () => void;

dtsPropsFor.Modal:
/** Dialog heading. */
  title?: React.ReactNode;
  /** Called on close (backdrop click, the × button, or Escape). */
  onClose: () => void;
  /** Dialog body. */
  children?: React.ReactNode;
  /** Widen the dialog (max-w-2xl instead of max-w-md). @default false */
  wide?: boolean;

dtsPropsFor.Toggle:
/** Whether the switch is on. */
  on?: boolean;
  /** Called when the switch is toggled. */
  onChange?: () => void;

dtsPropsFor.Toast:
/** The toast to show, or null/undefined to render nothing. */
  toast?: {
    /** Message text. */
    msg: string;
    /** Visual tone. @default 'success' */
    type?: 'success' | 'error';
    /** Show a spinner instead of the status glyph. */
    loading?: boolean;
  } | null;

dtsPropsFor.LmsBadge:
/** LMS the item was synced from. Known: 'canvas' | 'blackboard' | 'google_classroom' | 'brightspace' | 'moodle' | 'sakai'; any other string renders with a default indigo accent. */
  source: 'canvas' | 'blackboard' | 'google_classroom' | 'brightspace' | 'moodle' | 'sakai' | (string & {});
  className?: string;

dtsPropsFor.PriorityBadge:
/** Assignment priority. Renders nothing for 'none' or an unknown value. */
  priority: 'high' | 'medium' | 'low' | (string & {});
  className?: string;

dtsPropsFor.EmptyState:
/** Headline. */
  title?: React.ReactNode;
  /** Optional supporting copy below the headline. */
  children?: React.ReactNode;
